settings.custom_liquid:
{%- comment -%}
  COZZYPAWS – COLLECTION MODERNE (Hero + Styles + Trust Bar)
  À coller dans une section "Liquid personnalisé" en haut de /collections/all
{%- endcomment -%}

<style>
  /* ===== Variables marque ===== */
  :root { --cp:#451318; --cream:#F1ECE6; }

  /* ===== HERO ===== */
  .cpc-hero{background:var(--cream);border-radius:20px;padding:28px;margin:0 0 18px;border:1px solid #e7e0da}
  .cpc-hero h1{margin:0 0 6px;font-size:34px;line-height:1.15;color:var(--cp)}
  .cpc-hero p{margin:0;font-size:15px;opacity:.9}
  .cpc-promo{display:flex;gap:10px;flex-wrap:wrap;margin-top:12px}
  .cpc-pill{background:#fff;border:1px dashed #d7cfc8;border-radius:999px;padding:8px 12px;font-size:13px}

  /* ===== Filtres & tri sticky ===== */
  .facets-container{position:sticky;top:64px;z-index:4;background:rgba(241,236,230,.92);
    backdrop-filter:saturate(160%) blur(6px);border:1px solid #e7e0da;border-radius:14px;padding:8px 12px;margin-bottom:14px}

  /* ===== Grille & cartes produits modernisées ===== */
  .collection .grid{gap:22px}
  .card-wrapper{transition:transform .18s ease, box-shadow .18s ease}
  .card-wrapper:hover{transform:translateY(-4px);box-shadow:0 10px 24px rgba(0,0,0,.06)}
  .card{border-radius:18px;overflow:hidden;border:1px solid #eee;background:#fff}
  .card__inner, .card__media, .media{background:#fff}
  .card-information{padding:10px 12px 14px}
  .card-information__text{line-height:1.35}
  .price{font-weight:700}
  .price .price__sale .price-item--regular{text-decoration:none;opacity:.55}
  .badge{background:var(--cream);color:var(--cp);border:1px solid #e3dcd5;border-radius:999px;padding:4px 10px}
  .quick-add__submit, .button--secondary{border-radius:12px;background:var(--cp);border-color:var(--cp)}
  .quick-add__submit:hover{filter:brightness(.95)}

  /* ===== Barre réassurance ===== */
  .cpc-trust{margin-top:22px;display:grid;grid-template-columns:1fr;gap:10px}
  .cpc-trust .item{display:flex;gap:10px;align-items:center;background:var(--cream);
    border:1px dashed #ddcfc5;border-radius:14px;padding:12px}
  @media(min-width:900px){.cpc-trust{grid-template-columns:repeat(4,1fr)}}

  /* ===== Ajustements mineurs ===== */
  .title-wrapper--self-padded-tablet-down{display:none;} /* masque le H1 par défaut de Dawn */
</style>

<!-- ===== HERO dynamique ===== -->
<div class="cpc-hero">
  <h1>{{ collection.title | escape }}</h1>
  <p>Tous nos indispensables CozzyPaws • Livraison 24–72h au Maroc • Paiement à la livraison</p>
  <div class="cpc-promo">
    <span class="cpc-pill">🔥 Offres & Packs</span>
    <span class="cpc-pill">🧼 Séchage rapide</span>
    <span class="cpc-pill">🐾 Confort & propreté</span>
  </div>
</div>

<!-- ===== Barre réassurance (affichée si produits présents) ===== -->
{% if collection.all_products_count > 0 %}
  <div class="cpc-trust">
    <div class="item">🚚 <b>Livraison 24–72h</b> au Maroc</div>
    <div class="item">💳 <b>Paiement à la livraison</b></div>
    <div class="item">🔄 <b>Retours 7 jours</b></div>
    <div class="item">🧵 <b>Fabriqué au Maroc</b></div>
  </div>
{% endif %}
